import{_ as t,o as r,c as e,a4 as o}from"./chunks/framework.CwFacL3z.js";const u=JSON.parse('{"title":"快速入門","description":"","frontmatter":{"outline":"deep","title":"快速入門"},"headers":[],"relativePath":"tw/introduction.md","filePath":"tw/introduction.md","lastUpdated":1773759614000}'),i={name:"tw/introduction.md"};function l(n,a,d,h,s,c){return r(),e("div",null,[...a[0]||(a[0]=[o(`<h1 id="快速入門" tabindex="-1">快速入門 <a class="header-anchor" href="#快速入門" aria-label="Permalink to &quot;快速入門&quot;">​</a></h1><p>歡迎來到字源形碼！這是一款入門簡單且性能強大的形碼輸入法。</p><h2 id="🎯-為什麼選擇字源形碼" tabindex="-1">🎯 為什麼選擇字源形碼？ <a class="header-anchor" href="#🎯-為什麼選擇字源形碼" aria-label="Permalink to &quot;🎯 為什麼選擇字源形碼？&quot;">​</a></h2><h3 id="簡單易學" tabindex="-1">簡單易學 <a class="header-anchor" href="#簡單易學" aria-label="Permalink to &quot;簡單易學&quot;">​</a></h3><ul><li><strong>僅 20 個核心字根</strong> - 相比五筆的 130+ 字根，大幅降低學習門檻</li><li><strong>30 分鐘上手</strong> - 新手也能快速掌握字根編碼</li><li><strong>符合直覺</strong> - 字根設計直觀，易於記憶</li></ul><h3 id="高效輸入" tabindex="-1">高效輸入 <a class="header-anchor" href="#高效輸入" aria-label="Permalink to &quot;高效輸入&quot;">​</a></h3><ul><li><strong>四碼定長</strong> - 最多輸入 4 個字母</li><li><strong>低重碼率</strong> - 打字流暢，無需頻繁選詞</li><li><strong>科學拆字</strong> - 基於漢字字源和結構，符合自然規律</li></ul><h3 id="適用廣泛" tabindex="-1">適用廣泛 <a class="header-anchor" href="#適用廣泛" aria-label="Permalink to &quot;適用廣泛&quot;">​</a></h3><ul><li>日常辦公、專業寫作、編程開發</li><li>Windows、macOS、Linux 全平台支持</li></ul><h2 id="🚀-快速開始" tabindex="-1">🚀 快速開始 <a class="header-anchor" href="#🚀-快速開始" aria-label="Permalink to &quot;🚀 快速開始&quot;">​</a></h2><h3 id="第一步-了解字根" tabindex="-1">第一步：了解字根 <a class="header-anchor" href="#第一步-了解字根" aria-label="Permalink to &quot;第一步：了解字根&quot;">​</a></h3><p>字源形碼基於 20 個核心字根，分佈在鍵盤的各個鍵位上：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q W E R T Y U I O P</span></span>
<span class="line"><span> A S D F G H J K L</span></span>
<span class="line"><span>  Z X C V B N M</span></span></code></pre></div><p>每個鍵位對應 1-2 個字根，字形相似的字根會安排在相近的鍵位。</p><h3 id="第二步-學習編碼" tabindex="-1">第二步：學習編碼 <a class="header-anchor" href="#第二步-學習編碼" aria-label="Permalink to &quot;第二步：學習編碼&quot;">​</a></h3><p>字源形碼的編碼規則：</p><ul><li><strong>一碼字</strong>：常用字一鍵輸入（如：我、人、的）</li><li><strong>二碼字</strong>：大部分常用字兩鍵輸入</li><li><strong>三碼字</strong>：大部分字三鍵輸入</li><li><strong>四碼字</strong>：複雜字四鍵輸入</li></ul><h3 id="第三步-開始練習" tabindex="-1">第三步：開始練習 <a class="header-anchor" href="#第三步-開始練習" aria-label="Permalink to &quot;第三步：開始練習&quot;">​</a></h3><p><a href="/tw/practice/top500">開始常用字根練習 →</a></p><h2 id="📖-學習建議" tabindex="-1">📖 學習建議 <a class="header-anchor" href="#📖-學習建議" aria-label="Permalink to &quot;📖 學習建議&quot;">​</a></h2><h3 id="新手路徑" tabindex="-1">新手路徑 <a class="header-anchor" href="#新手路徑" aria-label="Permalink to &quot;新手路徑&quot;">​</a></h3><ol><li><strong>Day 1</strong>：完成順序練習，熟悉所有字根（約 30-60 分鐘）</li><li><strong>Day 2-3</strong>：隨機練習鞏固記憶（每天 20-30 分鐘）</li><li><strong>Week 1-2</strong>：常用字根專項練習</li><li><strong>持續</strong>：在日常生活中使用，形成肌肉記憶</li></ol><h3 id="學習技巧" tabindex="-1">學習技巧 <a class="header-anchor" href="#學習技巧" aria-label="Permalink to &quot;學習技巧&quot;">​</a></h3><ul><li><strong>理解記憶</strong>：理解字根與漢字的關係，不要死記硬背</li><li><strong>多次重複</strong>：短時多次比長時間一次更有效</li><li><strong>實際應用</strong>：盡快在真實場景中使用</li><li><strong>錯題複習</strong>：重點練習錯誤字根</li></ul><h3 id="時間安排" tabindex="-1">時間安排 <a class="header-anchor" href="#時間安排" aria-label="Permalink to &quot;時間安排&quot;">​</a></h3><table tabindex="0"><thead><tr><th>階段</th><th>時間</th><th>目標</th></tr></thead><tbody><tr><td>入門期</td><td>1-3 天</td><td>掌握 20 個字根</td></tr><tr><td>練習期</td><td>1-2 週</td><td>正確率達到 80%</td></tr><tr><td>進階期</td><td>持續</td><td>速度達到 60 字/分鐘</td></tr></tbody></table><h2 id="🎓-練習模式" tabindex="-1">🎓 練習模式 <a class="header-anchor" href="#🎓-練習模式" aria-label="Permalink to &quot;🎓 練習模式&quot;">​</a></h2><p>我們提供了多種練習模式，幫助您循序漸進地學習：</p><table tabindex="0"><thead><tr><th>練習模式</th><th>說明</th><th>推薦階段</th></tr></thead><tbody><tr><td><a href="/tw/practice/top500">常用字根</a></td><td>專項練習高頻字根</td><td>入門期 ✅</td></tr><tr><td><a href="/tw/practice/modern">順序練習</a></td><td>按順序學習所有字根</td><td>練習期 ✅</td></tr><tr><td><a href="/tw/practice/random">隨機練習</a></td><td>隨機抽測字根</td><td>進階期 ✅</td></tr><tr><td><a href="/tw/practice/error">錯題本</a></td><td>練習錯誤字根</td><td>持續 ✅</td></tr></tbody></table><h2 id="❓-常見問題" tabindex="-1">❓ 常見問題 <a class="header-anchor" href="#❓-常見問題" aria-label="Permalink to &quot;❓ 常見問題&quot;">​</a></h2><h3 id="q-多久能學會" tabindex="-1">Q：多久能學會？ <a class="header-anchor" href="#q-多久能學會" aria-label="Permalink to &quot;Q：多久能學會？&quot;">​</a></h3><p><strong>A</strong>：一般 30 分鐘可以掌握 20 個字根，1-2 週內可以熟練使用。</p><h3 id="q-和五筆相比有什麼優勢" tabindex="-1">Q：和五筆相比有什麼優勢？ <a class="header-anchor" href="#q-和五筆相比有什麼優勢" aria-label="Permalink to &quot;Q：和五筆相比有什麼優勢？&quot;">​</a></h3><p><strong>A</strong>：字根更少（20個 vs 130+），學習曲線更平緩，上手更快。</p><h3 id="q-打字速度能達到多少" tabindex="-1">Q：打字速度能達到多少？ <a class="header-anchor" href="#q-打字速度能達到多少" aria-label="Permalink to &quot;Q：打字速度能達到多少？&quot;">​</a></h3><p><strong>A</strong>：經過 1-2 週練習，大多數用戶可以達到每分鐘 60 字以上。</p><h3 id="q-適合零基礎新手嗎" tabindex="-1">Q：適合零基礎新手嗎？ <a class="header-anchor" href="#q-適合零基礎新手嗎" aria-label="Permalink to &quot;Q：適合零基礎新手嗎？&quot;">​</a></h3><p><strong>A</strong>：非常適合！字源形碼專為降低學習門檻而設計，新手也能快速上手。</p><h2 id="🔧-下載安裝" tabindex="-1">🔧 下載安裝 <a class="header-anchor" href="#🔧-下載安裝" aria-label="Permalink to &quot;🔧 下載安裝&quot;">​</a></h2><p><a href="http://ziyuan.ysepan.com/" target="_blank" rel="noreferrer">字源安裝包下載</a></p><p>支持 Windows、安卓 雙平台。</p><h2 id="🤝-社區支持" tabindex="-1">🤝 社區支持 <a class="header-anchor" href="#🤝-社區支持" aria-label="Permalink to &quot;🤝 社區支持&quot;">​</a></h2><ul><li><strong>QQ 群</strong>：點擊頁面右上角 QQ 圖標加入</li><li><strong>官方網站</strong>：<a href="http://ziyuan.ysepan.com/" target="_blank" rel="noreferrer">字源資源站</a></li></ul><h2 id="💡-立即開始" tabindex="-1">💡 立即開始 <a class="header-anchor" href="#💡-立即開始" aria-label="Permalink to &quot;💡 立即開始&quot;">​</a></h2><p>準備好開始學習了嗎？</p><p><a href="/tw/practice/top500">開始常用字根練習 →</a></p><hr><p>祝您學習愉快，打字效率節節高升！</p>`,48)])])}const b=t(i,[["render",l]]);export{u as __pageData,b as default};
